pipeline.evaluate:
(async () => {
  let attempts = 0;

  while (attempts < 20) {
    const removeBtn = document.querySelector('[data-testid="removeBookmark"]');
    if (removeBtn) return [{ status: 'success', message: 'Tweet is already bookmarked' }];

    const bookmarkBtn = document.querySelector('[data-testid="bookmark"]');
    if (bookmarkBtn) {
      bookmarkBtn.click();
      await new Promise(r => setTimeout(r, 1000));
      const verify = document.querySelector('[data-testid="removeBookmark"]');
      if (verify) return [{ status: 'success', message: 'Tweet successfully bookmarked' }];
      return [{ status: 'failed', message: 'Bookmark action initiated but UI did not update' }];
    }

    await new Promise(r => setTimeout(r, 500));
    attempts++;
  }

  return [{ status: 'failed', message: 'Could not find Bookmark button' }];
})()
